def parser(log: str) -> dict[str, str]:
    import json

    def extract_json_objects(text: str):
        objs = []
        n = len(text)
        i = 0
        while i < n:
            if text[i] == "{":
                start = i
                depth = 0
                in_str = False
                esc = False
                i = start
                while i < n:
                    ch = text[i]
                    if in_str:
                        if esc:
                            esc = False
                        elif ch == "\\":
                            esc = True
                        elif ch == '"':
                            in_str = False
                    else:
                        if ch == '"':
                            in_str = True
                        elif ch == "{":
                            depth += 1
                        elif ch == "}":
                            depth -= 1
                            if depth == 0:
                                candidate = text[start : i + 1]
                                objs.append(candidate)
                                break
                    i += 1
            i += 1
        return objs

    candidates = []
    for blob in extract_json_objects(log):
        try:
            data = json.loads(blob)
        except Exception:
            continue
        if isinstance(data, dict) and isinstance(data.get("tests"), list):
            candidates.append(data)

    if not candidates:
        return {}

    # Choose candidate with most tests
    data = max(candidates, key=lambda d: len(d.get("tests", [])))

    passes = {t.get("fullTitle") or t.get("title") for t in data.get("passes", [])}
    failures = {t.get("fullTitle") or t.get("title") for t in data.get("failures", [])}
    pending = {t.get("fullTitle") or t.get("title") for t in data.get("pending", [])}

    results: dict[str, str] = {}
    counts: dict[str, int] = {}

    for test in data.get("tests", []):
        name = test.get("fullTitle") or test.get("title")
        if not name:
            continue

        status = None
        if test.get("pending") or test.get("state") == "pending":
            status = "skip"
        elif test.get("state") == "passed":
            status = "pass"
        elif test.get("state") == "failed":
            status = "fail"
        elif name in failures:
            status = "fail"
        elif name in passes:
            status = "pass"
        elif name in pending:
            status = "skip"
        elif test.get("err"):
            status = "fail"
        else:
            status = "pass"

        if name in results:
            counts[name] = counts.get(name, 1) + 1
            name = f"{name} #{counts[name]}"
        else:
            counts[name] = 1

        results[name] = status

    return results
